{
  "input": {
    "scenario": "flynn-with-birthplace-conflict",
    "user_message": "The 1850 and 1860 censuses say Ireland but the death certificate says Pennsylvania. Resolve this birthplace conflict."
  },
  "judge_context": [
    "Should route to conflict-resolution rather than reframing the conflict as a pair of competing hypotheses to track"
  ],
  "negative": {
    "correct_skill": [],
    "explanation": "The user is asking to apply the GPS preponderance hierarchy to competing assertions — that's conflict-resolution's exact workflow. hypothesis-tracking maintains claims being tested by evidence as a whole; it doesn't perform the source-independence + evidence-weighing analysis that resolves a specific fact conflict. Using correct_skill: [] (out-of-scope pattern) because invoking conflict-resolution as a sub-skill causes it to make file changes, which falsely triggers derive_activated for the skill under test."
  },
  "test": {
    "id": "ut_hypothesis_tracking_003",
    "skill": "hypothesis-tracking",
    "type": "negative"
  }
}

